// Drawing canvas using pressure
import { useRef, useEffect } from 'react';

export function PressureCanvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d')!;
    let drawing = false;
    let last = { x: 0, y: 0 };

    const onDown = (e: PointerEvent) => {
      drawing = true;
      const r = canvas.getBoundingClientRect();
      last = { x: e.clientX - r.left, y: e.clientY - r.top };
    };

    const onMove = (e: PointerEvent) => {
      if (!drawing) return;
      const r = canvas.getBoundingClientRect();
      const x = e.clientX - r.left;
      const y = e.clientY - r.top;

      // Default pressure of 0.5 if not available (mouse)
      const pressure = e.pressure > 0 ? e.pressure : 0.5;

      ctx.lineWidth = pressure * 6;
      ctx.lineCap = 'round';
      ctx.beginPath();
      ctx.moveTo(last.x, last.y);
      ctx.lineTo(x, y);
      ctx.stroke();

      last = { x, y };
    };

    const onUp = () => { drawing = false; };

    canvas.addEventListener('pointerdown', onDown);
    canvas.addEventListener('pointermove', onMove);
    canvas.addEventListener('pointerup', onUp);
    canvas.addEventListener('pointercancel', onUp);

    return () => {
      canvas.removeEventListener('pointerdown', onDown);
      canvas.removeEventListener('pointermove', onMove);
      canvas.removeEventListener('pointerup', onUp);
      canvas.removeEventListener('pointercancel', onUp);
    };
  }, []);

  return <canvas ref={canvasRef} width={800} height={600} className="block bg-white" style={{ touchAction: 'none' }} />;
}

