import { useEffect } from 'react';

export function useCenterOnFocus(formRef: React.RefObject<HTMLElement>) {
  useEffect(() => {
    const form = formRef.current;
    if (!form) return;

    const onFocusIn = (e: FocusEvent) => {
      const target = e.target as HTMLElement;
      if (!target.matches('input, textarea, select')) return;

      setTimeout(() => {
        const vv = window.visualViewport;
        const rect = target.getBoundingClientRect();
        const visibleTop = vv?.offsetTop ?? 0;
        const visibleH = vv?.height ?? window.innerHeight;
        const desiredCenter = visibleTop + visibleH / 2;
        const elCenter = rect.top + rect.height / 2;
        const delta = elCenter - desiredCenter;

        if (Math.abs(delta) > 20) {
          window.scrollBy({ top: delta, behavior: 'smooth' });
        }
      }, 300);
    };

    form.addEventListener('focusin', onFocusIn);
    return () => form.removeEventListener('focusin', onFocusIn);
  }, [formRef]);
}

