import { useEffect } from 'react';

export function useUndoGesture(onUndo: () => void) {
  useEffect(() => {
    let startX = 0;
    let startTouches = 0;

    const onTouchStart = (e: TouchEvent) => {
      if (e.touches.length === 3) {
        startTouches = 3;
        startX = (e.touches[0].clientX + e.touches[1].clientX + e.touches[2].clientX) / 3;
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      if (startTouches === 3 && e.touches.length === 3) {
        const currentX = (e.touches[0].clientX + e.touches[1].clientX + e.touches[2].clientX) / 3;
        if (currentX - startX > 100) {
          onUndo();
          startTouches = 0;
        }
      }
    };

    const onTouchEnd = () => { startTouches = 0; };

    document.addEventListener('touchstart', onTouchStart);
    document.addEventListener('touchmove', onTouchMove);
    document.addEventListener('touchend', onTouchEnd);

    return () => {
      document.removeEventListener('touchstart', onTouchStart);
      document.removeEventListener('touchmove', onTouchMove);
      document.removeEventListener('touchend', onTouchEnd);
    };
  }, [onUndo]);
}

