'use client';
import { useParams, useRouter } from 'next/navigation';
import { useBreakpoint } from '@/hooks/useBreakpoint';

export function FolderFileLayout({ folders, files, filePreview }: { folders: React.ReactNode; files: React.ReactNode; filePreview: React.ReactNode }) {
  const params = useParams() as { folderId?: string; fileId?: string };
  const router = useRouter();
  const bp = useBreakpoint();

  if (bp === 'mobile') {
    if (params.fileId) {
      return (
        <div>
          <button onClick={() => router.push(`/folders/${params.folderId}`)} aria-label="Back">←</button>
          {filePreview}
        </div>
      );
    }
    if (params.folderId) {
      return (
        <div>
          <button onClick={() => router.push('/folders')} aria-label="Back">←</button>
          {files}
        </div>
      );
    }
    return folders;
  }

  return (
    <div className="grid h-dvh grid-cols-[240px_280px_1fr] divide-x">
      <aside>{folders}</aside>
      <aside>{params.folderId ? files : <Empty />}</aside>
      <main>{params.fileId ? filePreview : <Empty />}</main>
    </div>
  );
}

