// components/ImageCompare.tsx
import { useRef, useState } from 'react';

export function ImageCompare({ before, after, alt }: { before: string; after: string; alt: string }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [pos, setPos] = useState(50);

  const onPointerMove = (e: React.PointerEvent) => {
    if (!containerRef.current || (e.buttons === 0 && e.pointerType === 'mouse')) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const pct = (x / rect.width) * 100;
    setPos(Math.max(0, Math.min(100, pct)));
  };

  return (
    <div
      ref={containerRef}
      onPointerMove={onPointerMove}
      onPointerDown={onPointerMove}
      className="relative w-full aspect-video overflow-hidden bg-neutral-200"
      style={{ touchAction: 'none' }}
    >
      <img src={before} alt={`Before: ${alt}`} className="absolute inset-0 h-full w-full object-cover" />
      <img
        src={after}
        alt={`After: ${alt}`}
        className="absolute inset-0 h-full w-full object-cover"
        style={{ clipPath: `inset(0 ${100 - pos}% 0 0)` }}
      />
      <div
        role="slider"
        aria-valuenow={pos}
        aria-valuemin={0}
        aria-valuemax={100}
        aria-label="Compare slider"
        tabIndex={0}
        onKeyDown={(e) => {
          if (e.key === 'ArrowLeft') setPos((p) => Math.max(0, p - 5));
          if (e.key === 'ArrowRight') setPos((p) => Math.min(100, p + 5));
        }}
        className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize"
        style={{ left: `${pos}%`, transform: 'translateX(-50%)' }}
      >
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 h-10 w-10 rounded-full bg-white shadow-lg" />
      </div>
    </div>
  );
}

