import { createContext, useContext } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

type Device = {
  canHover: boolean;
  pointerCoarse: boolean;
  prefersReducedMotion: boolean;
  prefersDark: boolean;
  prefersReducedData: boolean;
  prefersContrast: boolean;
};

const Ctx = createContext<Device | null>(null);

export function DeviceProvider({ children }: { children: React.ReactNode }) {
  const device: Device = {
    canHover: useMediaQuery('(hover: hover)', false),
    pointerCoarse: useMediaQuery('(pointer: coarse)', true),
    prefersReducedMotion: useMediaQuery('(prefers-reduced-motion: reduce)', false),
    prefersDark: useMediaQuery('(prefers-color-scheme: dark)', false),
    prefersReducedData: useMediaQuery('(prefers-reduced-data: reduce)', false),
    prefersContrast: useMediaQuery('(prefers-contrast: more)', false),
  };
  return <Ctx.Provider value={device}>{children}</Ctx.Provider>;
}

export const useDevice = () => {
  const c = useContext(Ctx);
  if (!c) throw new Error('DeviceProvider missing');
  return c;
};

