// components/VideoWithPip.tsx
import { useRef, useState, useEffect } from 'react';
import { PictureInPicture2 } from 'lucide-react';

export function VideoWithPip({ src }: { src: string }) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [pipSupported, setPipSupported] = useState(false);

  useEffect(() => {
    setPipSupported(document.pictureInPictureEnabled);
  }, []);

  const togglePip = async () => {
    if (!videoRef.current) return;
    if (document.pictureInPictureElement) {
      await document.exitPictureInPicture();
    } else {
      await videoRef.current.requestPictureInPicture();
    }
  };

  return (
    <div className="relative">
      <video ref={videoRef} src={src} controls className="w-full aspect-video" />
      {pipSupported && (
        <button
          type="button"
          onClick={togglePip}
          aria-label="Picture in picture"
          className="absolute top-2 right-2 flex h-10 w-10 items-center justify-center rounded-full bg-black/40 text-white"
        ><PictureInPicture2 className="h-5 w-5" /></button>
      )}
    </div>
  );
}

