// components/CameraField.tsx
import { useState, useRef } from 'react';
import { Camera, X } from 'lucide-react';

export function CameraField({ onCapture }: { onCapture: (file: File) => void }) {
  const [preview, setPreview] = useState<string | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const onChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPreview(URL.createObjectURL(file));
    onCapture(file);
  };

  const retake = () => {
    setPreview(null);
    if (inputRef.current) inputRef.current.value = '';
  };

  return (
    <div>
      {preview ? (
        <div className="relative">
          <img src={preview} alt="Captured photo" className="w-full aspect-square object-cover rounded" />
          <button
            type="button"
            onClick={retake}
            aria-label="Retake photo"
            className="absolute top-2 right-2 flex h-10 w-10 items-center justify-center rounded-full bg-black/60 text-white"
          ><X className="h-5 w-5" /></button>
        </div>
      ) : (
        <label className="flex flex-col items-center gap-2 min-h-32 border-2 border-dashed rounded p-4 cursor-pointer hover:bg-neutral-50">
          <Camera className="h-8 w-8 text-neutral-400" />
          <span className="text-sm">Take photo</span>
          <input
            ref={inputRef}
            type="file"
            accept="image/*"
            capture="environment"
            onChange={onChange}
            className="sr-only"
          />
        </label>
      )}
    </div>
  );
}

